12	const PROCESSING_FEE = 5;
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	const FIRST_INSURANCE_MULTIPLIER = 1.1;
21	
22	const COMPONENT_TYPES = ["rune"];
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	// Base premium for `count` alike components: every full block of 3 costs
28	// the special block premium; leftover components are priced individually.
29	const componentBasePremium = (count: number): number => {
30	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
31	  const remainder = count % COMPONENT_BLOCK_SIZE;
32	  return blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
33	};
34	
35	// Round up in MHPCO's favour, guarding against floating-point noise
36	// (e.g. 197.50000000001 should still round to 198, not 199).
37	const roundUpInMHPCOFavor = (amount: number): number =>
38	  Math.ceil(Number(amount.toFixed(6)));
39	
40	export const quote = (
41	  items: Item[],
42	  customer: Customer,
43	  contractIndex: number,
44	): number => {
45	  const mainItems = items.filter((item) => !COMPONENT_TYPES.includes(item.type));
46	  const componentCount = items.filter((item) =>
47	    COMPONENT_TYPES.includes(item.type),
48	  ).length;
49	
50	  const mainBase = mainItems.reduce(
51	    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
52	    0,
53	  );
54	  const componentBase =
55	    componentBasePremium(componentCount) * FIRST_INSURANCE_MULTIPLIER;
56	
57	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
58	};
59	
60	export const claim = (): number => {
61	  return undefined as unknown as number;
62	};
